// Пользовательский сервер (serverEntry, обычный node-граф без react-server условия).
import express from 'express';
import path from 'node:path';

import { createRscExpress } from '@alfalab/scripts-server/rsc/express';

import { rscHandler } from '../rsc/entry';

const app = express();

// в prod ассеты отдаёт сам сервер; в dev их перехватывает dev-server до прокси
app.use('/assets', express.static(path.resolve('.build/assets')));

app.use(createRscExpress(rscHandler));

app.listen(3000, () => {
    // eslint-disable-next-line no-console
    console.log('[example-rsc] app server on http://localhost:3000');
});
