'use server-entry';

// Страница — асинхронный серверный компонент.
// Директива 'use server-entry' даёт rspack точку для сбора entryJsFiles/entryCssFiles.
import { Counter } from '../components/counter';

import './home.css';

async function getServerData(): Promise<{ now: string; pid: number }> {
    // имитация похода за данными на сервере
    await new Promise((resolve) => {
        setTimeout(resolve, 10);
    });

    return { now: new Date().toISOString(), pid: process.pid };
}

export async function HomePage() {
    const data = await getServerData();

    return (
        <html lang='ru'>
            <head>
                <meta charSet='utf-8' />
                <title>example-rsc POC</title>
            </head>
            <body>
                <h1>RSC на arui-scripts</h1>
                <p data-testid='server-time'>
                    Отрендерено на сервере: {data.now} (pid {data.pid})
                </p>
                <Counter initial={5} />
            </body>
        </html>
    );
}
